// --- 3D CARD COMPONENT (FIXED & COMPLETE) ---
function TeamCard3D({ member, position }: { member: any; position: [number, number, number] }) {
  const mesh = useRef<THREE.Group>(null!)
  const [hovered, setHovered] = useState(false)

  useFrame((state) => {
    if (!mesh.current) return
    
    const x = (state.mouse.x * Math.PI) / 10
    const y = (state.mouse.y * Math.PI) / 10
    
    mesh.current.rotation.x = THREE.MathUtils.lerp(
      mesh.current.rotation.x, 
      hovered ? -y * 0.3 : 0, 
      0.1
    )
    mesh.current.rotation.y = THREE.MathUtils.lerp(
      mesh.current.rotation.y, 
      hovered ? x * 0.3 : 0, 
      0.1
    )
    
    const targetScale = hovered ? 1.15 : 1
    mesh.current.scale.setScalar(
      THREE.MathUtils.lerp(mesh.current.scale.x, targetScale, 0.12)
    )
  })

  return (
    <group position={position} ref={mesh}>
      <Float speed={2} rotationIntensity={0.3} floatIntensity={0.6}>
        {/* Main Image Plane */}
        <mesh 
          onPointerOver={(e) => {
            e.stopPropagation()
            setHovered(true)
          }} 
          onPointerOut={(e) => {
            e.stopPropagation()
            setHovered(false)
          }}
        >
          <planeGeometry args={[2.8, 3.8]} />
          <meshStandardMaterial color="#222" transparent opacity={0.9} />
          <Suspense fallback={null}>
            <Image 
              url={member.image || "https://via.placeholder.com/300x400/1e293b/ffffff?text=Team+Member"} 
              transparent 
              position={[0, 0, 0.01]}
            />
          </Suspense>
        </mesh>

        {/* Glow Background */}
        <mesh position={[0, 0, -0.15]}>
          <planeGeometry args={[3.2, 4.2]} />
          <MeshDistortMaterial 
            color={hovered ? "#6366f1" : "#1e293b"} 
            speed={3} 
            distort={hovered ? 0.4 : 0.2} 
            radius={1.2}
          />
        </mesh>

        {/* Name Text */}
        <Text
          position={[0, -2.2, 0.3]}
          fontSize={0.22}
          color="white"
          maxWidth={2.8}
          textAlign="center"
          font="/fonts/Inter-Bold.woff"
          anchorX="center"
          anchorY="middle"
        >
          {member.name}
        </Text>

        {/* Role Text */}
        <Text
          position={[0, -2.7, 0.3]}
          fontSize={0.14}
          color="#94a3b8"
          maxWidth={2.8}
          textAlign="center"
          font="/fonts/Inter-Regular.woff"
          anchorX="center"
          anchorY="middle"
        >
          {member.role}
        </Text>
      </Float>
    </group>
  )
}

